export default {
	data() {
		return {
			dialogVisible: false,
			loading: false,
			id: null,
			form: {
				title: '',
				content: '',
				operTime: ''
			},
			rules: {
				title: [
					{ required: true, message: '请输入公告标题', trigger: 'blur' },
					{ min: 2, max: 100, message: '长度在 2 到 100 个字符', trigger: 'blur' }
				],
				content: [
					{ required: true, message: '请输入公告内容', trigger: 'blur' },
					{ min: 5, max: 500, message: '长度在 5 到 500 个字符', trigger: 'blur' }
				]
			}
		}
	},
	methods: {
		// 根据ID获取公告信息
		getNoticeById() {
			const params = {
				pageNo: 1,
				pageSize: 10
			};
			if (this.id) {
				params.id = this.id;
			}

			this.$http.post('api/communityCtl/noticeList', params).then((resp) => {
				if (resp.data.code === 200 && resp.data.data.list && resp.data.data.list.length > 0) {
					const notice = resp.data.data.list.find(item => item.id === this.id) || resp.data.data.list[0];
					this.form = notice;
				}
			}).catch((error) => {
				console.error('获取公告信息失败:', error);
				this.$message.error('获取公告信息失败');
			});
		},
		submitForm() {
			this.$refs.form.validate((valid) => {
				if (valid) {
					this.loading = true;
					this.$http.post('api/communityCtl/updateNotice', {
						id: this.id,
						...this.form
					}).then((resp) => {
						this.loading = false;
						if (resp.data.code === 200) {
							this.$message.success('修改成功');
							this.closeDialog();
							this.$emit('refresh');
						} else {
							this.$message.error(resp.data.message || '修改失败');
						}
					}).catch(() => {
						this.loading = false;
						this.$message.error('修改失败，请稍后重试');
					});
				}
			});
		},
		closeDialog() {
			this.dialogVisible = false;
			this.$refs.form.resetFields();
			this.form = {
				title: '',
				content: '',
				operTime: ''
			};
			this.id = null;
		}
	}
}
